package com.example.insightflowserver.controller;

import com.example.insightflowserver.model.LabReport;
import com.example.insightflowserver.service.LabReportService;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

/**
 * Unit tests for UploadController.
 *
 * Tests the file upload endpoints and error handling for lab report processing.
 *
 * @author Muhammad Abu Ubaida Aljerah
 */
@ExtendWith(MockitoExtension.class)
class UploadControllerTest {

    @Mock
    private LabReportService labReportService;

    @Mock
    private MultipartFile multipartFile;

    @InjectMocks
    private UploadController uploadController;

    @Test
    void uploadFile_ShouldReturnLabReport_WhenProcessingSucceeds() throws IOException {
        // Given
        LabReport expectedReport = new LabReport();
        expectedReport.setPatientName("John Doe");

        when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        when(labReportService.extractAndPersist(any(MultipartFile.class), anyString())).thenReturn(expectedReport);

        // When
        ResponseEntity<LabReport> response = uploadController.uploadFile(multipartFile, "user123");

        // Then
        assertEquals(HttpStatus.OK, response.getStatusCode());
        assertNotNull(response.getBody());
        assertEquals("John Doe", response.getBody().getPatientName());
        verify(labReportService).extractAndPersist(multipartFile, "user123");
    }

    @Test
    void uploadFile_ShouldReturnBadRequest_WhenIllegalArgumentExceptionOccurs() throws IOException {
        // Given
        when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        when(labReportService.extractAndPersist(any(MultipartFile.class), anyString()))
            .thenThrow(new IllegalArgumentException("Invalid file"));

        // When
        ResponseEntity<LabReport> response = uploadController.uploadFile(multipartFile, "user123");

        // Then
        assertEquals(HttpStatus.BAD_REQUEST, response.getStatusCode());
        assertNull(response.getBody());
    }

    @Test
    void uploadFile_ShouldReturnInternalServerError_WhenUnexpectedExceptionOccurs() throws IOException {
        // Given
        when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        when(labReportService.extractAndPersist(any(MultipartFile.class), anyString()))
            .thenThrow(new RuntimeException("Unexpected error"));

        // When
        ResponseEntity<LabReport> response = uploadController.uploadFile(multipartFile, "user123");

        // Then
        assertEquals(HttpStatus.INTERNAL_SERVER_ERROR, response.getStatusCode());
        assertNull(response.getBody());
    }

    @Test
    void uploadFile_ShouldUseDefaultUserId_WhenUserIdNotProvided() throws IOException {
        // Given
        LabReport expectedReport = new LabReport();
        expectedReport.setPatientName("John Doe");

        lenient().when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        lenient().when(multipartFile.getContentType()).thenReturn("application/pdf");
        lenient().when(multipartFile.getBytes()).thenReturn("sample content".getBytes());
        when(labReportService.extractAndPersist(any(MultipartFile.class), eq("anonymous"))).thenReturn(expectedReport);

        // When
        ResponseEntity<LabReport> response = uploadController.uploadFile(multipartFile, null);

        // Then
        assertEquals(HttpStatus.OK, response.getStatusCode());
        assertNotNull(response.getBody());
        assertEquals("John Doe", response.getBody().getPatientName());
        verify(labReportService).extractAndPersist(multipartFile, "anonymous");
    }
}

package com.example.insightflowserver.controller;

import com.example.insightflowserver.model.LabReport;
import com.example.insightflowserver.service.LabReportService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.mock.web.MockMultipartFile;
import org.springframework.test.web.servlet.MockMvc;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.multipart;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Unit tests for UploadController.
 *
 * Tests the file upload endpoints and error handling for lab report processing.
 *
 * @author Muhammad Abu Ubaida Aljerah
 */
@WebMvcTest(UploadController.class)
class UploadControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private LabReportService labReportService;

    @Test
    void uploadFile_ShouldReturnLabReport_WhenProcessingSucceeds() throws Exception {
        // Given
        LabReport expectedReport = new LabReport();
        expectedReport.setPatientName("John Doe");

        MockMultipartFile file = new MockMultipartFile(
            "file", "test.pdf", "application/pdf", "sample content".getBytes());

        when(labReportService.extractAndPersist(any(), any())).thenReturn(expectedReport);

        // When & Then
        mockMvc.perform(multipart("/api/upload")
                .file(file)
                .param("userId", "user123"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.patientName").value("John Doe"));
    }

    @Test
    void uploadFile_ShouldReturnBadRequest_WhenIllegalArgumentExceptionOccurs() throws Exception {
        // Given
        MockMultipartFile file = new MockMultipartFile(
            "file", "test.pdf", "application/pdf", "sample content".getBytes());

        when(labReportService.extractAndPersist(any(), any()))
            .thenThrow(new IllegalArgumentException("Invalid file"));

        // When & Then
        mockMvc.perform(multipart("/api/upload")
                .file(file)
                .param("userId", "user123"))
            .andExpect(status().isBadRequest());
    }

    @Test
    void uploadFile_ShouldReturnInternalServerError_WhenUnexpectedExceptionOccurs() throws Exception {
        // Given
        MockMultipartFile file = new MockMultipartFile(
            "file", "test.pdf", "application/pdf", "sample content".getBytes());

        when(labReportService.extractAndPersist(any(), any()))
            .thenThrow(new RuntimeException("Unexpected error"));

        // When & Then
        mockMvc.perform(multipart("/api/upload")
                .file(file)
                .param("userId", "user123"))
            .andExpect(status().isInternalServerError());
    }

    @Test
    void uploadFile_ShouldUseDefaultUserId_WhenUserIdNotProvided() throws Exception {
        // Given
        LabReport expectedReport = new LabReport();
        expectedReport.setPatientName("John Doe");

        MockMultipartFile file = new MockMultipartFile(
            "file", "test.pdf", "application/pdf", "sample content".getBytes());

        when(labReportService.extractAndPersist(any(), eq("anonymous"))).thenReturn(expectedReport);

        // When & Then
        mockMvc.perform(multipart("/api/upload")
                .file(file))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.patientName").value("John Doe"));
    }
}

package com.example.insightflowserver.service;

import com.example.insightflowserver.model.LabReport;
import com.example.insightflowserver.repositories.LabReportRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.test.util.ReflectionTestUtils;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

/**
 * Unit tests for LabReportService.
 *
 * Tests the lab report processing functionality including OCR extraction,
 * data parsing, and database persistence operations.
 *
 * @author Muhammad Abu Ubaida Aljerah
 */
@ExtendWith(MockitoExtension.class)
class LabReportServiceTest {

    @Mock
    private LabReportRepository labReportRepository;

    @Mock
    private MultipartFile multipartFile;

    @InjectMocks
    private LabReportService labReportService;

    private LabReport sampleLabReport;

    @BeforeEach
    void setUp() {
        // Set the apiKey field that would normally be injected by @Value
        ReflectionTestUtils.setField(labReportService, "apiKey", "test-api-key");

        sampleLabReport = new LabReport();
        sampleLabReport.setPatientName("John Doe");
        sampleLabReport.setReportDate("2024-01-15");
        sampleLabReport.setResults(List.of());
    }

    @Test
    void extractAndPersist_ShouldHandleIOException() throws IOException {
        // Given
        when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        when(multipartFile.getContentType()).thenReturn("application/pdf");
        when(multipartFile.getBytes()).thenThrow(new IOException("File read error"));

        // When & Then
        assertThrows(IOException.class, () -> {
            labReportService.extractAndPersist(multipartFile, "user123");
        });

        // Verify that repository save was never called due to the exception
        verify(labReportRepository, never()).save(any(LabReport.class));
    }

    @Test
    void extractAndPersist_ShouldUseDefaultUserId_WhenUserIdNotProvided() throws IOException {
        // Given - simulate the service working by mocking repository save
        when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        when(multipartFile.getContentType()).thenReturn("application/pdf");
        when(multipartFile.getBytes()).thenReturn("sample content".getBytes());
        when(labReportRepository.save(any(LabReport.class))).thenReturn(sampleLabReport);

        // When
        LabReport result = labReportService.extractAndPersist(multipartFile, null);

        // Then
        assertNotNull(result);
        assertEquals("anonymous", result.getUserId());
        verify(labReportRepository).save(any(LabReport.class));
    }

    @Test
    void extractAndPersist_ShouldUseProvidedUserId() throws IOException {
        // Given
        when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        when(multipartFile.getContentType()).thenReturn("application/pdf");
        when(multipartFile.getBytes()).thenReturn("sample content".getBytes());
        when(labReportRepository.save(any(LabReport.class))).thenReturn(sampleLabReport);

        // When
        LabReport result = labReportService.extractAndPersist(multipartFile, "customUser");

        // Then
        assertNotNull(result);
        assertEquals("customUser", result.getUserId());
        verify(labReportRepository).save(any(LabReport.class));
    }

    @Test
    void extractAndPersist_ShouldHandleRepositoryException() throws IOException {
        // Given
        lenient().when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        lenient().when(multipartFile.getContentType()).thenReturn("application/pdf");
        lenient().when(multipartFile.getBytes()).thenReturn("sample content".getBytes());
        when(labReportRepository.save(any(LabReport.class))).thenThrow(new RuntimeException("Database error"));

        // When & Then
        assertThrows(RuntimeException.class, () -> {
            labReportService.extractAndPersist(multipartFile, "user123");
        });
    }
}

package com.example.insightflowserver.service;

import com.example.insightflowserver.model.LabReport;
import com.example.insightflowserver.repositories.LabReportRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.Spy;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.test.util.ReflectionTestUtils;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

/**
 * Unit tests for LabReportService.
 *
 * Tests the lab report processing functionality including OCR extraction,
 * data parsing, and database persistence operations.
 *
 * @author Muhammad Abu Ubaida Aljerah
 */
@ExtendWith(MockitoExtension.class)
class LabReportServiceTest {

    @Mock
    private LabReportRepository labReportRepository;

    @Mock
    private MultipartFile multipartFile;

    @Spy
    @InjectMocks
    private LabReportService labReportService;

    private LabReport sampleLabReport;

    @BeforeEach
    void setUp() {
        // Set the apiKey field that would normally be injected by @Value
        ReflectionTestUtils.setField(labReportService, "apiKey", "test-api-key");

        sampleLabReport = new LabReport();
        sampleLabReport.setPatientName("John Doe");
        sampleLabReport.setReportDate("2024-01-15");
        sampleLabReport.setResults(List.of());
    }

    @Test
    void extractAndPersist_ShouldHandleIOException() throws IOException {
        // Given
        lenient().when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        lenient().when(multipartFile.getContentType()).thenReturn("application/pdf");
        when(multipartFile.getBytes()).thenThrow(new IOException("File read error"));

        // When & Then
        assertThrows(IOException.class, () -> {
            labReportService.extractAndPersist(multipartFile, "user123");
        });

        // Verify that repository save was never called due to the exception
        verify(labReportRepository, never()).save(any(LabReport.class));
    }

    @Test
    void extractAndPersist_ShouldUseDefaultUserId_WhenUserIdNotProvided() throws IOException {
        // Given
        lenient().when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        lenient().when(multipartFile.getContentType()).thenReturn("application/pdf");
        lenient().when(multipartFile.getBytes()).thenReturn("sample content".getBytes());

        // Mock the extractStructureReport method to avoid API calls
        doReturn(sampleLabReport).when(labReportService).extractStructureReport(any(byte[].class));
        when(labReportRepository.save(any(LabReport.class))).thenReturn(sampleLabReport);

        // When
        LabReport result = labReportService.extractAndPersist(multipartFile, null);

        // Then
        assertNotNull(result);
        assertEquals("anonymous", result.getUserId());
        verify(labReportRepository).save(any(LabReport.class));
    }

    @Test
    void extractAndPersist_ShouldUseProvidedUserId() throws IOException {
        // Given
        lenient().when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        lenient().when(multipartFile.getContentType()).thenReturn("application/pdf");
        lenient().when(multipartFile.getBytes()).thenReturn("sample content".getBytes());

        // Mock the extractStructureReport method to avoid API calls
        doReturn(sampleLabReport).when(labReportService).extractStructureReport(any(byte[].class));
        when(labReportRepository.save(any(LabReport.class))).thenReturn(sampleLabReport);

        // When
        LabReport result = labReportService.extractAndPersist(multipartFile, "customUser");

        // Then
        assertNotNull(result);
        assertEquals("customUser", result.getUserId());
        verify(labReportRepository).save(any(LabReport.class));
    }

    @Test
    void extractAndPersist_ShouldHandleRepositoryException() throws IOException {
        // Given
        lenient().when(multipartFile.getOriginalFilename()).thenReturn("test.pdf");
        lenient().when(multipartFile.getContentType()).thenReturn("application/pdf");
        lenient().when(multipartFile.getBytes()).thenReturn("sample content".getBytes());

        // Mock the extractStructureReport method to avoid API calls
        doReturn(sampleLabReport).when(labReportService).extractStructureReport(any(byte[].class));
        when(labReportRepository.save(any(LabReport.class))).thenThrow(new RuntimeException("Database error"));

        // When & Then
        assertThrows(RuntimeException.class, () -> {
            labReportService.extractAndPersist(multipartFile, "user123");
        });
    }
}
